# HuggingFace — rope_scaling config for context extension
from transformers import AutoModelForCausalLM, AutoConfig

config = AutoConfig.from_pretrained("meta-llama/Llama-2-7b-hf")
config.rope_scaling = {
    "type": "linear",
    "factor": 4.0          # extend 4096 → 16384 tokens
}
# or NTK-aware:
config.rope_scaling = {
    "type": "dynamic",
    "factor": 4.0
}
model = AutoModelForCausalLM.from_config(config)
